import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getTickets } from '../services/api';

const MOCK_TICKETS = [
  { id: 'TKT-001', priority: 'High', status: 'In Progress', title: 'Laptop not turning on', desc: 'My laptop completely stopped working after the Windows update last night.', category: 'Hardware', date: 'Apr 17, 08:30 AM' },
  { id: 'TKT-002', priority: 'Medium', status: 'Open', title: 'WiFi keeps disconnecting', desc: 'Internet connection drops every 10-15 minutes on my workstation.', category: 'Network', date: 'Apr 17, 09:15 AM' },
  { id: 'TKT-003', priority: 'High', status: 'Resolved', title: 'Cannot access company email', desc: 'Outlook is showing authentication error since this morning.', category: 'Software', date: 'Apr 16, 02:00 PM' },
  { id: 'TKT-004', priority: 'Medium', status: 'Resolved', title: 'Printer not responding', desc: 'Office printer on 3rd floor is offline and not printing any jobs.', category: 'Hardware', date: 'Apr 16, 11:30 AM' },
  { id: 'TKT-005', priority: 'Medium', status: 'In Progress', title: 'System running very slow', desc: 'My computer takes 10+ minutes to boot and applications freeze frequently.', category: 'Software', date: 'Apr 17, 07:45 AM' },
  { id: 'TKT-006', priority: 'Low', status: 'Resolved', title: 'Forgot VPN password', desc: 'Cannot connect to company VPN, password reset required.', category: 'Network', date: 'Apr 15, 04:00 PM' },
  { id: 'TKT-007', priority: 'Low', status: 'Open', title: 'Monitor flickering', desc: 'Second monitor keeps flickering and sometimes goes black.', category: 'Hardware', date: 'Apr 17, 10:00 AM' },
  { id: 'TKT-008', priority: 'High', status: 'Open', title: 'Software license expired', desc: 'Adobe Creative Suite showing license expired error.', category: 'Software', date: 'Apr 17, 11:20 AM' },
];

const STATUS_ICONS = { 'Open': '○', 'In Progress': '↻', 'Resolved': '✓' };
const CAT_ICONS = { 'Hardware': '🖥️', 'Software': '💻', 'Network': '📶' };

function PriorityBadge({ p }) {
  return <span className={p === 'High' ? 'priority-high' : p === 'Medium' ? 'priority-medium' : 'priority-low'}>{p}</span>;
}
function StatusBadge({ s }) {
  return <span className={s === 'In Progress' ? 'status-progress' : s === 'Open' ? 'status-open' : 'status-resolved'}>{STATUS_ICONS[s]} {s}</span>;
}

export default function MyTickets() {
  const navigate = useNavigate();
  const [tickets, setTickets] = useState(MOCK_TICKETS);
  const [filter, setFilter] = useState('All');
  const [search, setSearch] = useState('');
  const [priority, setPriority] = useState('All Priorities');
  const [category, setCategory] = useState('All Categories');

  useEffect(() => {
    getTickets().then(res => setTickets(res.data)).catch(() => {});
  }, []);

  const filtered = tickets.filter(t => {
    const matchStatus = filter === 'All' || t.status === filter;
    const matchSearch = t.title.toLowerCase().includes(search.toLowerCase()) || t.desc.toLowerCase().includes(search.toLowerCase());
    const matchPriority = priority === 'All Priorities' || t.priority === priority;
    const matchCat = category === 'All Categories' || t.category === category;
    return matchStatus && matchSearch && matchPriority && matchCat;
  });

  const total = tickets.length;
  const open = tickets.filter(t => t.status === 'Open').length;
  const inprogress = tickets.filter(t => t.status === 'In Progress').length;
  const resolved = tickets.filter(t => t.status === 'Resolved').length;

  return (
    <div>
      {/* Header */}
      <div className="px-20 pt-8 pb-0 flex items-start justify-between">
        <div>
          <div className="badge-green mb-3">🎟️ Ticket Management</div>
          <h1 className="font-head font-black text-4xl text-gray-900">My Tickets</h1>
        </div>
        <button className="btn-primary mt-2" onClick={() => navigate('/raise-ticket')}>+ New Ticket</button>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-4 px-20 py-6">
        {[[total, 'Total', '📋', ''], [open, 'Open', '○', ''], [inprogress, 'In Progress', '↻', 'amber'], [resolved, 'Resolved', '✓', 'green']].map(([num, label, icon, color]) => (
          <div key={label} className={`card p-5 flex items-center gap-4 ${color === 'amber' ? 'bg-amber-50 border-amber-200' : color === 'green' ? 'bg-green-light border-green/20' : ''}`}>
            <span className="text-xl">{icon}</span>
            <div>
              <div className={`font-head font-black text-3xl ${color === 'amber' ? 'text-amber-500' : color === 'green' ? 'text-green-dark' : 'text-gray-900'}`}>{num}</div>
              <div className="text-sm text-gray-500">{label}</div>
            </div>
          </div>
        ))}
      </div>

      {/* Toolbar */}
      <div className="px-20 pb-4 flex items-center gap-3 flex-wrap">
        <div className="relative flex-1 min-w-64">
          <span className="absolute left-3.5 top-1/2 -translate-y-1/2 text-sm">🔍</span>
          <input
            className="form-input pl-10"
            placeholder="Search tickets..."
            value={search}
            onChange={e => setSearch(e.target.value)}
          />
        </div>
        <div className="flex bg-gray-100 rounded-xl p-1 gap-0.5">
          {['All', 'Open', 'In Progress', 'Resolved'].map(s => (
            <button key={s} onClick={() => setFilter(s)}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all border-none cursor-pointer ${filter === s ? 'bg-white text-gray-900 font-semibold shadow-sm' : 'bg-transparent text-gray-500 hover:text-gray-700'}`}>
              {s}
            </button>
          ))}
        </div>
        <select className="form-input w-36" value={priority} onChange={e => setPriority(e.target.value)}>
          <option>All Priorities</option>
          <option>High</option>
          <option>Medium</option>
          <option>Low</option>
        </select>
        <select className="form-input w-40" value={category} onChange={e => setCategory(e.target.value)}>
          <option>All Categories</option>
          <option>Hardware</option>
          <option>Software</option>
          <option>Network</option>
        </select>
      </div>

      {/* Tickets Grid */}
      <div className="grid grid-cols-2 gap-4 px-20 pb-16">
        {filtered.map(t => (
          <div key={t.id} className="card p-6 hover:-translate-y-0.5 hover:shadow-lg transition-all cursor-pointer">
            <div className="flex items-center justify-between mb-2.5">
              <div className="flex items-center gap-2">
                <span className="text-xs font-semibold text-gray-400">{t.id}</span>
                <PriorityBadge p={t.priority} />
              </div>
              <StatusBadge s={t.status} />
            </div>
            <h3 className="font-head font-bold text-base mb-1.5">{t.title}</h3>
            <p className="text-sm text-gray-500 leading-relaxed mb-4">{t.desc}</p>
            <div className="flex items-center justify-between">
              <span className="text-xs text-gray-400">{CAT_ICONS[t.category]} {t.category} &nbsp;🕐 {t.date}</span>
              <button className="text-sm font-semibold text-green hover:text-green-dark transition-colors bg-transparent border-none cursor-pointer">View Details</button>
            </div>
          </div>
        ))}
        {filtered.length === 0 && (
          <div className="col-span-2 text-center py-16 text-gray-400">
            <div className="text-5xl mb-4">🔍</div>
            <div className="font-head font-semibold text-lg">No tickets found</div>
            <div className="text-sm mt-1">Try adjusting your filters</div>
          </div>
        )}
      </div>
    </div>
  );
}
